package osrm

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"strings"

	"github.com/dinno7/ride-sharing/services/trip-service/internal/application/ports"
	"github.com/dinno7/ride-sharing/shared/types"
)

type osrmRouteCalculator struct{}

func NewRouteCalculator() ports.RouteCalculator {
	return &osrmRouteCalculator{}
}

type osrmResponse struct {
	Code   string `json:"code"`
	Routes []struct {
		Distance float64 `json:"distance"`
		Duration float64 `json:"duration"`
		Geometry struct {
			Coordinates [][]float64 `json:"coordinates"`
			Type        string      `json:"type"`
		} `json:"geometry"`
		Legs []struct {
			Distance float64 `json:"distance"`
			Duration float64 `json:"duration"`
			Steps    []any   `json:"steps"`
			Summary  string  `json:"summary"`
			Weight   float64 `json:"weight"`
		} `json:"legs"`
		Weight     float64 `json:"weight"`
		WeightName string  `json:"weight_name"`
	} `json:"routes"`
	Waypoints []struct {
		Distance float64   `json:"distance"`
		Hint     string    `json:"hint"`
		Location []float64 `json:"location"`
		Name     string    `json:"name"`
	} `json:"waypoints"`
}

func (rc *osrmRouteCalculator) CalcRoutes(
	pickup, destination *types.Coordinate,
) (*types.Route, error) {
	osrmRes, err := getOSRMRoutes(pickup, destination)
	if err != nil {
		return nil, err
	}

	if strings.ToLower(osrmRes.Code) != "ok" {
		return nil, errors.New("osrm's response code is not ok")
	}

	coordinates := []*types.Coordinate{}
	for _, g := range osrmRes.Routes[0].Geometry.Coordinates {
		lng, lat := g[0], g[1]
		if lng != 0 && lat != 0 {
			cordinate := types.Coordinate{
				Longitude: lng,
				Latitude:  lat,
			}
			coordinates = append(coordinates, &cordinate)
		}
	}

	return &types.Route{
		Distance: osrmRes.Routes[0].Distance,
		Duration: osrmRes.Routes[0].Duration,
		Geometry: []*types.Geometry{
			{Coordinates: coordinates},
		},
	}, nil
}

func getOSRMRoutes(pickup, destination *types.Coordinate) (*osrmResponse, error) {
	url := fmt.Sprintf(
		"http://router.project-osrm.org/route/v1/driving/%f,%f;%f,%f?overview=full&geometries=geojson",
		pickup.Longitude,
		pickup.Latitude,
		destination.Longitude,
		destination.Latitude,
	)
	result, err := http.Get(url)
	if err != nil {
		return nil, err
	}
	var osrmRes osrmResponse
	if err := json.NewDecoder(result.Body).Decode(&osrmRes); err != nil {
		return nil, err
	}

	return &osrmRes, nil
}

func getOSRMRoutesMock(pickup, destination *types.Coordinate) (*osrmResponse, error) {
	var osrmRes osrmResponse
	if err := json.Unmarshal([]byte(mockJson), &osrmRes); err != nil {
		return nil, err
	}
	return &osrmRes, nil
}

